		["bm_ring_aesliip"] = "Волшебное кольцо, некогда принадлежавшее Драугру-Лорду Эслипу (Aesliip) в пещерах под озером Фьялдинг на острове Солстхейм.",
		["bm_ring_marksman"] = "Волшебное кольцо, найденное в дупле дерева недалеко от пиршественного зала Тирск на Солстхейме.",
		["bm_ring_view"] = "Волшебное кольцо, найденное в пасти чучела скального наездника в Большом Зале Деревни Скаалов, Солстхейм.",
		["bm_nordic01_robe_whitewalk"] = "Мантия, созданная бывшим членом Гильдии магов Фриссой (Fryssa), убитой собственным творением в пещере Бенконгерике на острове Солстхейм.",
		["mantle of woe"] = "Мантии, найденные начинающим некромантом Тимваулом (Tymvaul) в ледяной пещере Римхалл под Деревней Скаалов на острове Солстхейм.",
		["light_com_lantern_bm_unique"] = "Уникальный долговечный фонарь, сделанный из стекла и железа, излучает непревзойденный радиус света.",
		-- Уникальные предметы официальных плагинов
		["helm_tohan_unique"] = "Легендарный адамантитовый шлем, найденный в даэдрическом святилище Оннисиралис. Шлем Тохана обладает необычайно высоким потенциалом для зачарования.",
		["ward of akavir"] = "Легендарный драконий чешуйчатый щит, найденный в форте Файрмот, островной крепости, однажды завоеванной личем Грурном и его скелетной армией.",
		-- Kogoruhn Expanded
		["dk_dagoth_pauld_l_uni"] = "Созданные давно в забытом мотиве Неоплаканного Племени, наплечники Шестого Дома — одни из редчайших артефактов времен расцвета дома Дагот.",
		["dk_dagoth_pauld_r_uni"] = "Созданные давно в забытом мотиве Неоплаканного Племени, наплечники Шестого Дома — одни из редчайших артефактов времен расцвета дома Дагот.",
		["dk_robe_morin"] = "Формальные мантии Дагота Морина (Dagoth Morin), жреца Шестого Дома, погребенного в крепости Когорун.",
		-- King's Oath Fix
		["king's_oath"] = "Мощные церемониальные клинки, даваемые только тем, кто поклялся служить королю Хлаалу Хелсету. Говорят, что Клятва Короля несет на себе смертельные проклятия, предназначенные для убийства воров и предателей, и вручается только тем, кто прошел великие испытания.",
		-- Face of the Hortator
		["1fh_dae_hortator"] = "Легендарная церемониальная маска, предположительно изображающая лик Индорила Неревара. В отличие от богато украшенных изображений Индорила, Лик Наставника представляет более ужасный аспект прославленного героя — аспект падомаического чемпиона.",
		-- Salt Gems of Bensamsi
		["md_ashgem_chorpa_hammer"] = "Уникальный молот, сделанный из кристаллов хорпы и полученный от Джиты-Нан (Jitha-Nan) для помощи в его исследованиях в Бенсамси.",
		["md_ashgem_chorpa_hammer_v2"] = "Улучшенный молот, сделанный из кристаллов хорпы и полученный от Джиты-Нан (Jitha-Nan) для помощи в его исследованиях в Бенсамси.",
	}
this.artifactTable = {
		["misc_soulgem_azura"] = "Даэдрический артефакт, связанный с Азурой, Принцессой Сумерек. Звезда Азуры действует как многоразовая душа-камень, способная многократно захватывать и освобождать души существ. Те даэдра, которые вернулись в свою форму, утверждают, что души, захваченные Звездой, обитают в ином месте, нежели те, что взяты обычными методами, возможно, в карманном измерении самой Принцессы.",
		["artifact_bittercup_01"] = "Даэдрический артефакт, связанный с Клавикусом Вайлом, Принцем Сделок. Горькая Чаша идеально иллюстрирует сферу Принца — дарование силы и желаний через ритуальные призывы и сделки. Говорят, что тот, кто выпьет ее нектар, увидит резкое усиление своих величайших способностей, хотя и ценой дальнейшего ослабления своих недостатков.",
		["ebony_bow_auriel"] = "Аэдрический артефакт, связанный с Ауриэлем, Альдмерским Богом Времени. Лук Ауриэля — одно из величайших оружий, когда-либо существовавших в истории Тамриэля. Согласно легенде, Лук использовался в Эру Рассвета самим Великим Богом Времени против сил Лорхана, и якобы черпал силу из самого Этериуса, направляемую через Магнуса. В конце концов Ауриэль прикрепил сердце Обманщика к стреле и отправил ее в море, где образовалась Красная Гора.",
		["ebony_shield_auriel"] = "Аэдрический артефакт, связанный с Ауриэлем, Альдмерским Богом Времени. Щит Ауриэля — один из величайших щитов в истории Тамриэля. Согласно легенде, Щит использовался в Эру Рассвета самим Великим Богом Времени против сил Лорхана, сдерживая силы первобытного человека от мифического эльфийского дома Альдмерис.",
		["boots of blinding speed[unique]"] = "Один из более сомнительных артефактов Тамриэля, эти сапоги из кожи нетча даруют владельцу огромное увеличение скорости, но оставляют его слепым, как Жреца Мотылька.",
		["glass dagger_symmachus_unique"] = "Церемониальный стеклянный кинжал покойного короля Морнхолда, Симмаха (Symmachus). Симмах был данмерским генералом Тибера Септима, мужем Барензии и отцом короля Хлаалу Хелсета. Во время Имперского Симулякра он пал в битве против восставших крестьян в Морнхолде, и этот кинжал перешел от отца к сыну.",
		["tenpaceboots"] = "Названные в честь скорости и акробатических способностей, даруемых владельцу, сапоги «Десять Шагов» сделаны из простой тяжелой кожи, но вдохновили народные сказки и слухи о великих ограблениях и смелых погонях на протяжении эпох, всегда появляясь случайным образом в истории.",
		["daedric warhammer_ttgd"] = "Таинственный даэдрический боевой молот, полученный от Тарера Ротелота (Tharer Rotheloth) из Храма Трибунала для использования в убийстве Раксла Берна (Raxle Berne) и его вампирского клана.",
		["cleaverstfelms"] = "Священный артефакт Храма Трибунала. Говорят, что этот топор принадлежал святому Фелмсу Смелому (Saint Felms the Bold), покровителю мясников и торговцев рыбой.",
		["wraithguard"] = "Легендарная рукавица, созданная тональным архитектором лордом Кагренаком из двемеров для манипуляции Сердцем Лорхана. Wraithguard — единственное средство избежать смертельных эффектов при использовании кинжала Keening или молота Sunder.",
		["wraithguard_jury_rig"] = "Легендарная рукавица, созданная тональным архитектором лордом Кагренаком из двемеров для манипуляции Сердцем Лорхана. Wraithguard — единственное средство избежать смертельных эффектов при использовании кинжала Keening или молота Sunder.",
		["keening"] = "Легендарный кинжал, созданный тональным архитектором лордом Кагренаком из двемеров для манипуляции Сердцем Лорхана. Keening рассекает и фокусирует богоподобную силу, производимую Sunder, позволяя направлять ее волей владельца.",
		["sunder"] = "Легендарный молот, созданный тональным архитектором лордом Кагренаком из двемеров для манипуляции Сердцем Лорхана. Sunder производит определенное количество и качество богоподобной силы из Сердца при ударе.",
		["artifact_amulet of heartfire"] = "Таинственное ожерелье шестого дома, некогда носимое Даготом Одросом (Dagoth Odros) в цитадели Одросал.",
		["artifact_amulet of heartheal"] = "Таинственное ожерелье шестого дома, некогда носимое Даготом Вемином (Dagoth Vemyn) в цитадели Веминал.",
		["artifact_amulet of heartrime"] = "Таинственное ожерелье шестого дома, некогда носимое Даготом Эндусом (Dagoth Endus) в цитадели Эндусал.",
		["artifact_amulet of heartthrum"] = "Таинственное ожерелье шестого дома, некогда носимое Даготом Турейнулом (Dagoth Tureynul) в цитадели Турейнулал.",
		["amulet_usheeja"] = "Таинственный амулет, найденный в хранилищах Башни Сумерек у Призрачных Врат.",
		["madstone"] = "Зачарованная семейная реликвия, полученная от племени Ахеммуса, признающая Нереварина, Военачальника Ахеммуса и Защитника Народа.",
		["teeth"] = "Зачарованная семейная реликвия, полученная от племени Уршилаку, признающая Нереварина, Военачальника Уршилаку и Защитника Народа.",
		["thong"] = "Зачарованная семейная реликвия, полученная от племени Зайнаб, признающая Нереварина, Военачальника Зайнаб и Защитника Народа.",
		["belt of heartfire"] = "Таинственный пояс шестого дома, некогда носимый Даготом Утолом (Dagoth Uthol) в руинах Когорун.",
		["seizing"] = "Зачарованная семейная реликвия, полученная от племени Эрабенимсун, признающая Нереварина, Чемпиона Эрабенимсун и Защитника Народа.",
		["blood ring"] = "Таинственное кольцо шестого дома, некогда носимое Даготом Гилвотом (Dagoth Gilvoth) в цитадели Дагот Ур.",
		["heart ring"] = "Таинственное кольцо шестого дома, найденное в Фабричной пещере цитадели Дагот Ур.",
		["moon_and_star"] = "Легендарное кольцо Индорила Неревара, созданное тональным архитектором лордом Кагренаком из двемеров и благословленное даэдрической богиней Азурой. Это кольцо дало Неревару возможность объединить враждующие кланы химеров и сформировать Первый Совет вместе с дварфами.",
		["soul ring"] = "Таинственное кольцо шестого дома, некогда носимое Даготом Арайнисом (Dagoth Araynys) в пещерах Мамея.",
		["expensive_shirt_hair"] = "Священный артефакт Храма Трибунала. Говорят, что эта рубашка, сделанная из волос, принадлежала святому Аралору Кающемуся (Saint Aralor the Penitent), покровителю дубильщиков и шахтеров.",
		["shoes of st. rilms"] = "Священный артефакт Храма Трибунала. Говорят, что эта обувь принадлежала святой Рильмс Босой (Saint Rilms the Barefooted), покровительнице паломников и нищих.",
		["necromancers_amulet_uniq"] = "Творение печально известного Маннимарко, Короля Червей. Амулет Некроманта — одна из последних сохранившихся реликвий Некроманта, дарующая любому заклинателю, носящему его, способность регенерировать от травм и поглощать магику, делая носителя мудрым не по годам.",
		["skeleton_key"] = "Даэдрический артефакт, связанный с Ноктюрнал, Принцессой Тени. Скелетный Ключ позволяет обойти любые замки. Однако Ключ имеет ограниченное количество применений как из-за ограничений, наложенных параноидальными волшебниками, так и из-за его собственной склонности прятаться. Несмотря на кажущуюся простоту функции, говорят, что артефакт обладает еще большими способностями метафизического значения, возможно, способными открывать не только материальные замки.",
		["dwarven_hammer_volendrung"] = "Даэдрический артефакт, связанный с Малакатом, Принцем Изгоев. Volendrung, как говорят, был создан дварфийским кланом Руркен, поселившимся в том, что сейчас является Хаммерфеллом, за сотни лет до того, как они исчезли из мира Тамриэля. Говорят, что они бросили молот через континент, прежде чем покинуть свой дом в Морровинде, решив поселиться там, где он приземлится. Как и дварфы, создавшие его, Volendrung склонен внезапно исчезать, появляясь снова иногда через дни, иногда через эоны.",
		["crosierstllothis"] = "Священный артефакт Храма Трибунала. Говорят, что этот посох принадлежал святому Ллотису Благочестивому (Saint Llothis the Pious), покровителю портных и красильщиков.",
		["katana_bluebrand_unique"] = "Даэдрический артефакт, связанный с Боэтией, Принцессой Заговоров. Eltonbrand — истинный облик клинка Goldbrand. Говорят, он был создан северными драконами и подарен великому рыцарю, поклявшемуся защищать их. Высвободив всю силу Боэтии, что обитает внутри, золотой клинок способен сжигать всех, кого поражает, одновременно усиливая возможности владельца.",
		["fork_horripilation_unique"] = "Обычная на вид железная вилка, Вилка Ужаса давно является любимицей Безумного Бога среди его многочисленных артефактов, созданных, чтобы издеваться над смертными.",
		["robe of st roris"] = "Священный артефакт Храма Трибунала. Говорят, что эта мантия принадлежала святому Рорису Мученику (Saint Roris the Martyr), покровителю мебельщиков и караванщиков.",
		["sanguineamuletenterprise"] = "Амулет, представляющий одну из двадцати семи легендарных Нитей Прядильщицы, некогда принадлежавший Эно Хлаалу (Eno Hlaalu) из Мораг Тонг.",
		["sanguineamuletglibspeech"] = "Амулет, представляющий одну из двадцати семи легендарных Нитей Прядильщицы, некогда принадлежавший Шотере (Shotherra) из Хуула.",
		["sanguineamuletnimblearmor"] = "Амулет, представляющий одну из двадцати семи легендарных Нитей Прядильщицы, некогда принадлежавший Севере Магии (Severa Magia) из Альд Сота.",
		["sanguinebeltbalancedarmor"] = "Пояс, представляющий одну из двадцати семи легендарных Нитей Прядильщицы, некогда принадлежавший Реласу Аротану (Relas Arothan) из Ассернерайрана.",
		["sanguinebeltdeepbiting"] = "Пояс, представляющий одну из двадцати семи легендарных Нитей Прядильщицы, некогда принадлежавший Реласу Аротану (Relas Arothan) из Ассернерайрана.",
		["sanguinebeltdenial"] = "Пояс, представляющий одну из двадцати семи легендарных Нитей Прядильщицы, некогда принадлежавший Мовису Дарису (Movis Darys) из Гильдии магов Альд'Руна.",
		["sanguinebeltfleetness"] = "Пояс, представляющий одну из двадцати семи легендарных Нитей Прядильщицы, некогда принадлежавший Хрордис (Hrordis) в таверне «Полпути» в Пелагиаде.",
		["sanguinebelthewing"] = "Пояс, представляющий одну из двадцати семи легендарных Нитей Прядильщицы, некогда принадлежавший Дурусу Мариусу (Durus Marius) из Ассернерайрана.",
		["sanguinebeltimpaling"] = "Пояс, представляющий одну из двадцати семи легендарных Нитей Прядильщицы, некогда принадлежавший Глуронку гра-Шуле (Gluronk gra-Shula) в таверне «У врат» в Садрит Море.",
		["sanguinebeltmartialcraft"] = "Пояс, представляющий одну из двадцати семи легендарных Нитей Прядильщицы, некогда принадлежавший Карекальмо (Carecalmo) из Ашалмимилкалы.",
		["sanguinebeltsmiting"] = "Пояс, представляющий одну из двадцати семи легендарных Нитей Прядильщицы, некогда принадлежавший Домбе (Domba) из Альд Дэдрота.",
		["sanguinebeltstolidarmor"] = "Пояс, представляющий одну из двадцати семи легендарных Нитей Прядильщицы, некогда принадлежавший Миндели Сарен (Mindeli Saren) из Ясамиддана.",
		["sanguinebeltsureflight"] = "Пояс, представляющий одну из двадцати семи легендарных Нитей Прядильщицы, некогда принадлежавший Дурусу Мариусу (Durus Marius) из Ассернерайрана.",
		["sanguinerglovehornyfist"] = "Перчатка, представляющая одну из двадцати семи легендарных Нитей Прядильщицы, некогда принадлежавшая Гурилу Ретерану (Guril Retheran) в лавке «Золотые цветы» в городе Вивек.",
		["sanguinelglovesafekeeping"] = "Перчатка, представляющая одну из двадцати семи легендарных Нитей Прядильщицы, некогда принадлежавшая Инганару (Inganar) из Уларрадаллаку.",
		["sanguinergloveswiftblade"] = "Перчатка, представляющая одну из двадцати семи легендарных Нитей Прядильщицы, некогда принадлежавшая Севере Магии (Severa Magia) из Альд Сота.",
		["sanguineringfluidevasion"] = "Кольцо, представляющее одну из двадцати семи легендарных Нитей Прядильщицы, некогда принадлежавшее Севере Магии (Severa Magia) из Альд Сота.",
		["sanguineringgoldenw"] = "Кольцо, представляющее одну из двадцати семи легендарных Нитей Прядильщицы, некогда принадлежавшее Талис Веран (Talis Veran) из Эбернанита.",
		["sanguineringgreenw"] = "Кольцо, представляющее одну из двадцати семи легендарных Нитей Прядильщицы, некогда принадлежавшее Грызу-Зуб (Gnaw Tooth) из Альд Дэдрота.",
		["sanguineringredw"] = "Кольцо, представляющее одну из двадцати семи легендарных Нитей Прядильщицы, некогда принадлежавшее Лландрале Варам (Llandrale Varam) из Альд Сота.",
		["sanguineringsilverw"] = "Кольцо, представляющее одну из двадцати семи легендарных Нитей Прядильщицы, некогда принадлежавшее Эармилу (Earmil) из Ассурнабиташпи.",
		["sanguineringsublimew"] = "Кольцо, представляющее одну из двадцати семи легендарных Нитей Прядильщицы, некогда принадлежавшее Анель Ретелас (Anel Rethelas) из Ясамиддана.",
		["sanguineringtranscendw"] = "Кольцо, представляющее одну из двадцати семи легендарных Нитей Прядильщицы, некогда принадлежавшее Лландрале Варам (Llandrale Varam) из Альд Сота.",
		["sanguineringtransfigurw"] = "Кольцо, представляющее одну из двадцати семи легендарных Нитей Прядильщицы, некогда принадлежавшее Лландрале Варам (Llandrale Varam) из Альд Сота.",
		["sanguineringunseenw"] = "Кольцо, представляющее одну из двадцати семи легендарных Нитей Прядильщицы, некогда принадлежавшее Эрундилу (Erundil) из Индораньона.",
		["sanguineshoesleaping"] = "Обувь, представляющая одну из двадцати семи легендарных Нитей Прядильщицы, некогда принадлежавшая Дро'Займару (Dro'Zaymar) из округа Св. Делина города Вивек.",
		["sanguineshoesstalking"] = "Обувь, представляющая одну из двадцати семи легендарных Нитей Прядильщицы, некогда принадлежавшая Товаси Алену (Thovasi Alen) из Ассарнатамата.",
		-- Tribunal
		["mace of slurring"] = "Легендарная булава, созданная ближе к концу Второй Эры Кьянкой (Kyanka), безумным альтмерским оружейником и заклинателем. У него было довольно извращенное чувство юмора, и он, очевидно, наслаждался мыслью о том, чтобы превратить противников в бессвязно лепечущих, прежде чем раздавить их насмерть.",
		["stendar_hammer_unique"] = "Священный артефакт Восьмерых (Девяти). Говорят, что Молот Стэндарра когда-то был в руках самого божества Стэндарра. Сделанный из эбонита и сапфира, молот, возможно, является самым тяжелым оружием в Тамриэле: четыре человека понадобились только для того, чтобы поднять его на музейный подиум в городе Морнхолд.",
		["sword of almalexia"] = "Легендарный клинок Амалексии, Надежда-Огонь (Hopesfire), был аналогом собственного клинка Индорила Неревара, Истинного Пламени (Trueflame); оба меча были преподнесены в качестве свадебных даров паре дварфийским королем Думаком.",
		["nerevarblade_01_flame"] = "Легендарный клинок Неревара, Истинное Пламя (Trueflame), был аналогом Надежды-Огня Амалексии; оба меча были преподнесены в качестве свадебных даров паре дварфийским королем Думаком. Хотя Истинное Пламя было разбито в Первую Эру в Битве у Красной Горы, оно было восстановлено Инкарнатом.",
		["bipolar blade"] = "Согласно легенде, один дворянин потратил свое состояние на создание клинка высочайшей силы. Два кузнеца на противоположных концах Тамриэля должны были создать каждую половину клинка, не подозревая друг о друге, в надежде, что только владелец клинка узнает его истинную силу. Однако кузнецы создали половинки с чарами, которые полностью нейтрализовали друг друга, сделав клинок бесполезным для дворянина.",
		["robe_lich_unique"] = "Зачарованная давно «Личем Морнхолда», Гедной Рельвель (Gedna Relvel). Она была печально известной жрицей Храма Морнхолда, осужденной за использование запретной магии. Хотя она была похоронена в руинах Старого Морнхолда, ей удалось обмануть смерть и стать личем. Пробудившись спустя столетия, лич попытался распространить древнюю болезнь, известную как «Багровая Чума», но был уничтожен до того, как она смогла распространиться.",
		-- Bloodmoon
		["bm_mace_aevar_uni"] = "Согласно скаальской легенде, эпонимный герой, в честь которого названа эта булава, однажды вошел в Пещеру Скрытой Музыки по приказу Камня Земли и внутри ударил своей булавой по скале в такт Песне Земли, вернув Дар Земли скаалам и сделав землю снова богатой. Стальримовая булава с тех пор вручается тем немногим, кто завершает Ритуал Даров.",
		["bm_hunterspear_unique"] = "Даэдрический артефакт, связанный с Хирсином, Принцем Охоты. Копье Охотника ассоциируется с Кровавой Луной. Говорят, что только те охотники, которые могут посоревноваться в хитрости с самим Даэдротом во время его пребывания в Тамриэле, могут быть удостоены этого легендарного оружия.",
		["bm_ring_hircine"] = "Даэдрический артефакт, связанный с Хирсином, Принцем Охоты. Кольцо Хирсина позволяет пользоваться преимуществами дара Принца — ликантропии — без необходимости обрекать себя на этот недуг и следующую за ним жажду крови. Согласно легенде, кольцо обладает еще большими способностями, продлевая жизнь тех, кто его носит, среди прочих более таинственных эффектов.",
		-- TamLore
		["lords_cuirass_unique"] = "Священный артефакт Восьмерых (Девяти). Говорят, что Кираса Лорда была подарена смертным Кинарет, Богиней Ветров, и носилась крылатым человеком-быком Морихаусом против угнетателей-айлейдов ранних сиродиилов. Она остается с носителем только до тех пор, пока богиня считает его достойным, даруя ему способность поглощать здоровье, сопротивляться эффектам заклинаний и исцелять себя от яда.",
		["ebon_plate_cuirass_unique"] = "Даэдрический артефакт, связанный с Боэтией, Принцессой Заговоров. Эбонитовая Кольчуга (Ebony Mail) — это нагрудник, сделанный из редкого материала эбонита, который наделяет владельца устойчивостью к огню и магике, а также окутывает его магическим щитом.",
		["spell_breaker_unique"] = "Даэдрический артефакт, связанный с Перитом, Принцем Чумы. Spellbreaker защищает своего владельца, отражая магию и заставляя противников замолчать. Напоминающий двемерский башенный щит, он впервые был зафиксирован во время войны между кланом Руркен и легендарным магом Шалидором на территории современного Хаммерфелла.",
		["claymore_chrysamere_unique"] = "Известный многим как Клинок Паладина, Chrysamere — это мощный древний двуручный меч, дарующий своему владельцу здоровье, а также защиту от огня и заклинаний. Находившийся долгие годы во владении Имперского Легиона, этот меч недавно сменил владельца, как он, как известно, часто делает.",
		["staff_magnus_unique"] = "Аэдрический артефакт, связанный с Магнусом, Альдмерским Богом Магии, который служил Лорхану архитектором Мундуса. Этот посох когда-то служил метафизической батареей, но в руках смертных, кажется, ограничен поглощением жизненной энергии врагов. Перекликаясь с похожими рассказами о бегстве Магнуса из творения, образовавшего великую дыру в небе, которая освещает каждый день, Посох Магнуса, как говорят, бросает своих владельцев ради сохранения мистического баланса Аурбиса.",
		["ring_warlock_unique"] = "Аэдрический артефакт, связанный с Сирабейном, Альдмерским Богом Колдовства. Кольцо Чародея было разумно использовано могущественным магом, чтобы спасти многих от Трассианской Чумы в Первую Эру, что принесло этой фигуре место в храмах поклоняющихся аэдра мер. Известное прежде всего своей способностью отражать заклинания и ускорять владельца, кольцо никогда не задерживалось в одном месте достаточно долго, чтобы его полный потенциал был раскрыт.",
		["ring_phynaster_unique"] = "Аэдрический артефакт, связанный с Финастером, Альдмерским Богом Жизни, который создал это дающее сопротивление кольцо, чтобы помочь себе выжить в своих многочисленных приключениях. Говорят, что он научил альтмеров естественным образом жить еще сто лет, используя более короткий шаг. И они, и полуэльфы-бретонцы поклоняются этому божеству в храмах, посвященных аэдра.",
		["ring_khajiit_unique"] = "Даэдрический артефакт, первоначально принадлежавший Мефала, Принцессе Секретов. Говорят, что Кольцо Кхаджитов было украдено прямо с руки Принцессы Раджином, легендарным богом-вором народов Эльсвера. Дарующее невидимость и большую скорость, кольцо сделало его величайшим грабителем в их истории, пока кольцо не покинуло его. Используемое с тех пор для множества целей, неудивительно, что кольцо попало во владение даже других Даэдрических Принцев, таких как Меридия.",
		["mace of molag bal_unique"] = "Даэдрический артефакт, связанный с Молаг Балом, Принцем Доминирования. Говорят, что эта булава была выкована в глубинах его царства Холдхарбор и дается Принцем свободно, чтобы сеять смерть и разрушение на лике Нирна. Высасывая силу и магику из противников, это одно из самых извращенных орудий Обливиона, позволяющее использовать преимущества над врагами, подчиненными силой Булавы.",
		["daedric_helm_clavicusvile"] = "Даэдрический артефакт, связанный с Клавикусом Вайлом, Принцем Сделок. Маска (Masque) является свидетельством тщеславия Принца, созданная под его собственную личность. Поэтому она отражает на окружающих обаяние Даэдры, внушая уважение и восхищение независимо от внешности носителя. Однако она лучше всего используется в руках самых общительных и склонных к социальным играм.",
		["mehrunes'_razor_unique"] = "Даэдрический артефакт, связанный с Мерунесом Дагоном, Принцем Разрушения. Бритва (Razor) возвещает о кровавых переменах и резне, что очевидно из ее присутствия во время жестокой внутренней борьбы за власть, которая уничтожила Темное Братство, а также войны между телваннскими волшебниками Нелотом и Готреном. Эбонитовый кинжал, способный, как говорят, убивать мгновенно. Легенда гласит, что Бритва обладает еще большими, метафизическими способностями.",
		["cuirass_savior_unique"] = "Даэдрический артефакт, связанный с Хирсином, Принцем Охоты. Кираса Шкуры Спасителя (Cuirass of the Savior's Hide) наделяет владельца большой устойчивостью к магии. Согласно легенде, кираса сделана из собственной содранной шкуры Принца, дарованной первому чемпиону, которому удалось сбежать из его Охотничьих Угодий.",
		["spear_mercy_unique"] = "Предположительно даэдрического происхождения, Копье Горькой Милости (Spear of Bitter Mercy) известно своими великими оборонительными силами. Хотя оно окутано тайной, одна легенда рассказывает об использовании его великим героем, который сражался им против самого Мерунеса Дагона во время падения Боевого Шпиля (Battlespire).",
		["daedric_scourge_unique"] = "Даэдрический артефакт, связанный с Малакатом, Принцем Изгоев. Бич (Scourge) был создан Принцем, чтобы помочь смертному Маккану против сил Мерунеса Дагона, и теперь служит всем смертным против их даэдрических угнетателей. Некоторое время булава служила Теневому Легиону Имперского Боевого Шпиля против сил Бездны, но нашла новое предназначение после его падения.",
		["longbow_shadows_unique"] = "Даэдрический артефакт, связанный с Ноктюрнал, Принцессой Тени. Лук Теней (Bow of Shadows) дарует владельцу большую скорость и невидимость. Хотя многие его владельцы, естественно, остались в секрете, Лук был использован данмерским убийцей во времена Тибера Септима, чтобы убить принца Хаммерфелла А'тора во время Битвы при Хандинг-Бей, доставив эту провинцию Империи.",
		["gauntlet_fists_l_unique"] = "Некогда носимая могучим нордским воином по имени Рандагульф, эта рукавица оказалась во владении Верховного Короля Харальда после того, как он завоевал меньшие нордские королевства и основал Скайрим как полноценную нацию. Уважая Рандагульфа, Харальд хранил Кулаки (Fists) до своей смерти, наслаждаясь силой, которую они дарили ему в его последние годы.",
		["gauntlet_fists_r_unique"] = "Некогда носимая могучим нордским воином по имени Рандагульф, эта рукавица оказалась во владении Верховного Короля Харальда после того, как он завоевал меньшие нордские королевства и основал Скайрим как полноценную нацию. Уважая Рандагульфа, Харальд хранил Кулаки (Fists) до своей смерти, наслаждаясь силой, которую они дарили ему в его последние годы.",
		["claymore_iceblade_unique"] = "Легендарный двуручный меч, зачарованный печально известным Архимагом Альмионом Сельмо (Almion Celmo). Этот леденящий клинок предназначался для использования в заговоре против далекого короля, но его владелец провалил свою миссию, и Архимаг был заключен в тюрьму. Внутри, как говорят, обитает душа Морозного Монарха — высшей формы Морозного Атронаха, редко встречаемой за пределами царств Обливиона.",
		["ring_surrounding_unique"] = "Таинственное кольцо, которое, как говорят, позволяет сливаться с окружающей обстановкой, эффект, который, возможно, объясняет отсутствие историй о его использовании.",
		["boots_apostle_unique"] = "Священный артефакт Восьмерых (Девяти). Норды говорят, что Сапоги Апостола (Boots of the Apostle) носил сам Тибер Септим, когда спускался с высоких пиков Скайрима после того, как узнал секреты Серобородых, получив сапоги в подарок за свою хитрость и умение загадывать загадки.",
		["ring_mentor_unique"] = "Созданное Верховным Волшебником Ками Асрон (Cami Asron) для использования своими учениками, Кольцо Наставника (Mentor's Ring) — это артефакт, который должен ценить любой начинающий маг, способный значительно увеличить его магические возможности и эффективность.",
		["ring_wind_unique"] = "Священный артефакт Восьмерых (Девяти), Кольцо Ветра (Ring of the Wind) ассоциируется с Кинарет, Богиней Ветров, и особенно ценится в Эльсвере за свою способность улучшать ловкость и без того проворных каджитов.",
		["ring_vampiric_unique"] = "Среди более печально известных артефактов Тамриэля, Вампирическое Кольцо (Vampiric Ring) позволяет высасывать жизненную сущность из другого. Говорят, оно было создано в Морровинде культом последователей вампиров и редко появлялось на поверхности Тамриэля.",
		["towershield_eleidon_unique"] = "Созданный для Элейдона (Eleidon), знаменитого святого рыцаря бретонцев, Страж Элейдона (Eleidon's Ward), как говорят, способен исцелять даже самые тяжелые раны. Легенда гласит, что все богатства богатого барона были вложены в создание этого артефакта, чтобы отблагодарить Элейдона за спасение дочери барона.",
		["staff_hasedoki_unique"] = "Посох волшебника, который, как говорят, был величайшим в свое время. Хаседоки (Hasedoki) боялись за его силу, и те, кого он встречал, отвергали его. Не сумев найти другого волшебника, который разделял бы его участь, Хаседоки связал свою собственную душу с этим гравированным посохом, наделив его великой способностью сопротивляться магии.",
		["bloodworm_helm_unique"] = "Творение печально известного Маннимарко, Короля Червей. Шлем Кровавого Червя (Bloodworm Helm) ценится некромантами как дополнение к их ремеслу. Легенда гласит, что этот артефакт был создан Маннимарко незадолго до его предполагаемого вознесения к божественности во время Войны на Западе, когда Некромант принял форму Реванента, луны, вращающейся вокруг космического тела Аркея.",
		["dragonbone_cuirass_unique"] = "Сделанный из настоящей драконьей кости, этот кираса был зачарован первым Имперским Боевым Магом при императоре Тиберии Септиме, Зурином Арктусом. Свидетельствуя о его великом магическом мастерстве, владелец полностью устойчив к огню. Говорят, что Арктус был самым доверенным советником императора и помог заключить перемирие с Морровиндом, в результате которого Третья Империя получила колоссальный Нумидиум.",
		["warhammer_crusher_unique"] = "Невероятно легкий, несмотря на свою плотность, Сокрушитель Черепов (Skull Crusher) был создан в зачарованных огнях волшебника Дораха Гусала (Dorach Gusal) и выкован искусным кузнецом Хильбонгардом Роламом (Hilbongard Rolamus). Он предназначался для демонстрации на фестивале как свидетельство их способностей, но был украден. Легенда гласит, что боевой молот до сих пор путешествует по Тамриэлю в поисках своих создателей.",
		["katana_goldbrand_unique"] = "Даэдрический артефакт, связанный с Боэтией, Принцессой Заговоров. Goldbrand, как говорят, был создан северными драконами и подарен великому рыцарю, поклявшемуся защищать их. Содержащий силу Боэтии, золотой клинок способен сжигать всех, кого поражает. Хотя он достаточно мощен сам по себе, некоторые говорят, что у клинка есть еще больший потенциал, который еще предстоит раскрыть.",
		["dagger_fang_unique"] = "Вырезанный из зуба чернотопского вамасу по имени Хайнекхтнамет (Haynekhtnamet), Клык (Fang) был создан после того, как группа из семи северных мужчин убила зверя, и один из них вернулся домой с трофеем. Вамасу ранние норды считали драконами с кровью из молний, и их убийство считалось великим достижением. Те, кто создавал оружие из таких зверей, обнаруживали, что оно сохраняет часть магических свойств зверя.",
		["longsword_umbra_unique"] = "Даэдрический артефакт, связанный с Клавикусом Вайлом, Принцем Сделок. Меч Умбра (Umbra Sword) был зачарован древней ведьмой Наэнрой Ваэрр с частью его силы. Однако, отделившись от своего создателя, меч начал жить собственной жизнью, постепенно подавляя личность последующих владельцев, пока они тоже не начинали называть себя Умброй.",
		["ring_denstagmer_unique"] = "Таинственное кольцо, по-видимому, принадлежавшее некоему Денстагмеру (Denstagmer). Этот артефакт дарует владельцу защиту от различных элементов.",
		["helm_bearclaw_unique"] = "Даэдрический артефакт, связанный с Малакатом, Принцем Изгоев. Шлем Медвежий Коготь (Helm of Oreyn Bearclaw), как говорят, принадлежал герою Валенвуда, победившему печально известную ведьму-змею Гленхвайфаунву (Glenhwyfaunva), обеспечив существование своего клана. Он совершил множество других великих дел, прежде чем пасть от Кнахейтенской Чумы (Knahaten Flu), хотя есть и те, кто оспаривает его историю в целом.",
		["daedric_crescent_unique"] = "Уникальные клинки, использовавшиеся силами Мерунеса Дагона во время его штурма Имперского Боевого Шпиля (Battlespire). Даэдрические Полумесяцы (Daedric Crescents) были собраны и уничтожены после того, как магическая академия была отвоевана. Однако один, по-видимому, уцелел в руках Дремора-лорда Дрегаса Волари (Dregas Volar), изолированного в своем святилище Магас Волар.",
		-- Welkynd Stones
		["pb_welkyndstone"] = "Созданные древними айлейдами, которые когда-то властвовали над Сиродиилом, камни Велкайнд (Welkynd Stones) — это светящиеся куски ограненного и зачарованного метеоритного стекла, редкие фрагменты Этериуса, упавшие на Нирн. Их сила может быть извлечена за счет кристалла, восстанавливая большое количество магии для субъекта.",
		-- Bucklers Remastered
		["atl_art_targe_blooded"] = "Сделанный из простого дерева и железа, этот таинственный баклер, как говорят, имеет происхождение из провинции Скайрим, где его зазубренная поверхность когда-то была свидетельницей убийства бесчисленных местных снежных эльфов. Будь то по какой-то утерянной атморанской технологии или просто отреставрирован с тех пор, простые материалы проявляют мало признаков износа, несмотря на большой возраст щита.",
		-- Patch for Purists
		["glass dagger_symmachus_unique_x"] = "Церемониальный стеклянный кинжал покойного короля Морнхолда, Симмаха. Симмах был данмерским генералом Тибера Септима, мужем Барензии и отцом короля Хлаалу Хелсета. Во время Имперского Симулякра он пал в битве против восставших крестьян в Морнхолде, и этот кинжал перешел от отца к сыну.",
		["ebony_bow_auriel_x"] = "Аэдрический артефакт, связанный с Ауриэлем, Альдмерским Богом Времени. Лук Ауриэля — одно из величайших оружий, когда-либо существовавших в истории Тамриэля. Согласно легенде, Лук использовался в Эру Рассвета самим Великим Богом Времени против сил Лорхана, и якобы черпал силу из самого Этериуса, направляемую через Магнуса. В конце концов Ауриэль прикрепил сердце Обманщика к стреле и отправил ее в море, где образовалась Красная Гора.",
		["bipolar blade_x"] = "Согласно легенде, один дворянин потратил свое состояние на создание клинка высочайшей силы. Два кузнеца на противоположных концах Тамриэля должны были создать каждую половину клинка, не подозревая друг о друге, в надежде, что только владелец клинка узнает его истинную силу. Однако кузнецы создали половинки с чарами, которые полностью нейтрализовали друг друга, сделав клинок бесполезным для дворянина.",
		["spear_mercy_unique_x"] = "Предположительно даэдрического происхождения, Копье Горькой Милости известно своими великими оборонительными силами. Хотя оно окутано тайной, одна легенда рассказывает об использовании его великим героем, который сражался им против самого Мерунеса Дагона во время падения Боевого Шпиля.",
		["longbow_shadows_unique_x"] = "Даэдрический артефакт, связанный с Ноктюрнал, Принцессой Тени. Лук Теней дарует владельцу большую скорость и невидимость. Хотя многие его владельцы, естественно, остались в секрете, Лук был использован данмерским убийцей во времена Тибера Септима, чтобы убить принца Хаммерфелла А'тора во время Битвы при Хандинг-Бей, доставив эту провинцию Империи.",
		["claymore_chrysamere_unique_x"] = "Известный многим как Клинок Паладина, Chrysamere — это мощный древний двуручный меч, дарующий своему владельцу здоровье, а также защиту от огня и заклинаний. Находившийся долгие годы во владении Имперского Легиона, этот меч недавно сменил владельца, как он, как известно, часто делает.",
		["dagger_fang_unique_x"] = "Вырезанный из зуба чернотопского вамасу по имени Хайнекхтнамет, Клык был создан после того, как группа из семи северных мужчин убила зверя, и один из них вернулся домой с трофеем. Вамасу ранние норды считали драконами с кровью из молний, и их убийство считалось великим достижением. Те, кто создавал оружие из таких зверей, обнаруживали, что оно сохраняет часть магических свойств зверя.",
		["katana_goldbrand_unique_x"] = "Даэдрический артефакт, связанный с Боэтией, Принцессой Заговоров. Goldbrand, как говорят, был создан северными драконами и подарен великому рыцарю, поклявшемуся защищать их. Содержащий силу Боэтии, золотой клинок способен сжигать всех, кого поражает. Хотя он достаточно мощен сам по себе, некоторые говорят, что у клинка есть еще больший потенциал, который еще предстоит раскрыть.",
		["claymore_iceblade_unique_x"] = "Легендарный двуручный меч, зачарованный печально известным Архимагом Альмионом Сельмо. Этот леденящий клинок предназначался для использования в заговоре против далекого короля, но его владелец провалил свою миссию, и Архимаг был заключен в тюрьму. Внутри, как говорят, обитает душа Морозного Монарха — высшей формы Морозного Атронаха, редко встречаемой за пределами царств Обливиона.",
		["mace of molag bal_unique_x"] = "Даэдрический артефакт, связанный с Молаг Балом, Принцем Доминирования. Говорят, что эта булава была выкована в глубинах его царства Холдхарбор и дается Принцем свободно, чтобы сеять смерть и разрушение на лике Нирна. Высасывая силу и магику из противников, это одно из самых извращенных орудий Обливиона, позволяющее использовать преимущества над врагами, подчиненными силой Булавы.",
		["mace of slurring_x"] = "Легендарная булава, созданная ближе к концу Второй Эры Кьянкой, безумным альтмерским оружейником и заклинателем. У него было довольно извращенное чувство юмора, и он, очевидно, наслаждался мыслью о том, чтобы превратить противников в бессвязно лепечущих, прежде чем раздавить их насмерть.",
		["warhammer_crusher_unique_x"] = "Невероятно легкий, несмотря на свою плотность, Сокрушитель Черепов был создан в зачарованных огнях волшебника Дораха Гусала и выкован искусным кузнецом Хильбонгардом Роламом. Он предназначался для демонстрации на фестивале как свидетельство их способностей, но был украден. Легенда гласит, что боевой молот до сих пор путешествует по Тамриэлю в поисках своих создателей.",
		["staff_hasedoki_unique_x"] = "Посох волшебника, который, как говорят, был величайшим в свое время. Хаседоки боялись за его силу, и те, кого он встречал, отвергали его. Не сумев найти другого волшебника, который разделял бы его участь, Хаседоки связал свою собственную душу с этим гравированным посохом, наделив его великой способностью сопротивляться магии.",
		["staff_magnus_unique_x"] = "Аэдрический артефакт, связанный с Магнусом, Альдмерским Богом Магии, который служил Лорхану архитектором Мундуса. Этот посох когда-то служил метафизической батареей, но в руках смертных, кажется, ограничен поглощением жизненной энергии врагов. Перекликаясь с похожими рассказами о бегстве Магнуса из творения, образовавшего великую дыру в небе, которая освещает каждый день, Посох Магнуса, как говорят, бросает своих владельцев ради сохранения мистического баланса Аурбиса.",
		["stendar_hammer_unique_x"] = "Священный артефакт Восьмерых (Девяти). Говорят, что Молот Стэндарра когда-то был в руках самого божества Стэндарра. Сделанный из эбонита и сапфира, молот, возможно, является самым тяжелым оружием в Тамриэле: четыре человека понадобились только для того, чтобы поднять его на музейный подиум в городе Морнхолд.",
		["longsword_umbra_unique_x"] = "Даэдрический артефакт, связанный с Клавикусом Вайлом, Принцем Сделок. Меч Умбра был зачарован древней ведьмой Наэнрой Ваэрр с частью его силы. Однако, отделившись от своего создателя, меч начал жить собственной жизнью, постепенно подавляя личность последующих владельцев, пока они тоже не начинали называть себя Умброй.",
		["daedric warhammer_ttgd_x"] = "Таинственный даэдрический боевой молот, полученный от Тарера Ротелота из Храма Трибунала для использования в убийстве Раксла Берна и его вампирского клана.",
		["ebony_shield_auriel_x"] = "Аэдрический артефакт, связанный с Ауриэлем, Альдмерским Богом Времени. Щит Ауриэля — один из величайших щитов в истории Тамриэля. Согласно легенде, Щит использовался в Эру Рассвета самим Великим Богом Времени против сил Лорхана, сдерживая силы первобытного человека от мифического эльфийского дома Альдмерис.",
		["boots_apostle_unique_x"] = "Священный артефакт Восьмерых (Девяти). Норды говорят, что Сапоги Апостола носил сам Тибер Септим, когда спускался с высоких пиков Скайрима после того, как узнал секреты Серобородых, получив сапоги в подарок за свою хитрость и умение загадывать загадки.",
		["boots of blinding speed_x"] = "Один из более сомнительных артефактов Тамриэля, эти сапоги из кожи нетча даруют владельцу огромное увеличение скорости, но оставляют его слепым, как Жреца Мотылька.",
		["tenpaceboots_x"] = "Названные в честь скорости и акробатических способностей, даруемых владельцу, сапоги «Десять Шагов» сделаны из простой тяжелой кожи, но вдохновили народные сказки и слухи о великих ограблениях и смелых погонях на протяжении эпох, всегда появляясь случайным образом в истории.",
		["dragonbone_cuirass_unique_x"] = "Сделанный из настоящей драконьей кости, этот кираса был зачарован первым Имперским Боевым Магом при императоре Тиберии Септиме, Зурином Арктусом. Свидетельствуя о его великом магическом мастерстве, владелец полностью устойчив к огню. Говорят, что Арктус был самым доверенным советником императора и помог заключить перемирие с Морровиндом, в результате которого Третья Империя получила колоссальный Нумидиум.",
		["ebon_plate_cuirass_unique_x"] = "Даэдрический артефакт, связанный с Боэтией, Принцессой Заговоров. Эбонитовая Кольчуга — это нагрудник, сделанный из редкого материала эбонита, который наделяет владельца устойчивостью к огню и магике, а также окутывает его магическим щитом.",
		["towershield_eleidon_unique_x"] = "Созданный для Элейдона, знаменитого святого рыцаря бретонцев, Страж Элейдона, как говорят, способен исцелять даже самые тяжелые раны. Легенда гласит, что все богатства богатого барона были вложены в создание этого артефакта, чтобы отблагодарить Элейдона за спасение дочери барона.",
		["helm_bearclaw_unique_x"] = "Даэдрический артефакт, связанный с Малакатом, Принцем Изгоев. Шлем Медвежий Коготь, как говорят, принадлежал герою Валенвуда, победившему печально известную ведьму-змею Гленхвайфаунву, обеспечив существование своего клана. Он совершил множество других великих дел, прежде чем пасть от Кнахейтенской Чумы, хотя есть и те, кто оспаривает его историю в целом.",
		["bloodworm_helm_unique_x"] = "Творение печально известного Маннимарко, Короля Червей. Шлем Кровавого Червя ценится некромантами как дополнение к их ремеслу. Легенда гласит, что этот артефакт был создан Маннимарко незадолго до его предполагаемого вознесения к божественности во время Войны на Западе, когда Некромант принял форму Реванента, луны, вращающейся вокруг космического тела Аркея.",
		["lords_cuirass_unique_x"] = "Священный артефакт Восьмерых (Девяти). Говорят, что Кираса Лорда была подарена смертным Кинарет, Богиней Ветров, и носилась крылатым человеком-быком Морихаусом против угнетателей-айлейдов ранних сиродиилов. Она остается с носителем только до тех пор, пока богиня считает его достойным, даруя ему способность поглощать здоровье, сопротивляться эффектам заклинаний и исцелять себя от яда.",
		["cuirass_savior_unique_x"] = "Даэдрический артефакт, связанный с Хирсином, Принцем Охоты. Кираса Шкуры Спасителя наделяет владельца большой устойчивостью к магии. Согласно легенде, кираса сделана из собственной содранной шкуры Принца, дарованной первому чемпиону, которому удалось сбежать из его Охотничьих Угодий.",
		["spell_breaker_unique_x"] = "Даэдрический артефакт, связанный с Перитом, Принцем Чумы. Spellbreaker защищает своего владельца, отражая магию и заставляя противников замолчать. Напоминающий двемерский башенный щит, он впервые был зафиксирован во время войны между кланом Руркен и легендарным магом Шалидором на территории современного Хаммерфелла.",
	}
