		-- Daedric:
		["daedric arrow"] = "Одни из самых редких и ценных сокровищ Тамриэля. Даэдрические стрелы изготавливаются из сырого эбонита, очищенного в ритуале связывания с остатками даэдра, придающими предмету форму; сила оружия напрямую усиливается затяжными страданиями и яростью обитающего внутри даэдрота.",
		["daedric battle axe"] = "Одни из самых редких и ценных сокровищ Тамриэля. Даэдрические боевые топоры изготавливаются из сырого эбонита, очищенного в ритуале связывания с остатками даэдра, придающими предмету форму; сила оружия напрямую усиливается затяжными страданиями и яростью обитающего внутри даэдрота.",
		["daedric claymore"] = "Одни из самых редких и ценных сокровищ Тамриэля. Даэдрические двуручные мечи изготавливаются из сырого эбонита, очищенного в ритуале связывания с остатками даэдра, придающими предмету форму; сила оружия напрямую усиливается затяжными страданиями и яростью обитающего внутри даэдрота.",
		["daedric club"] = "Одни из самых редких и ценных сокровищ Тамриэля. Даэдрические дубины изготавливаются из сырого эбонита, очищенного в ритуале связывания с остатками даэдра, придающими предмету форму; сила оружия напрямую усиливается затяжными страданиями и яростью обитающего внутри даэдрота.",
		["daedric dagger"] = "Одни из самых редких и ценных сокровищ Тамриэля. Даэдрические кинжалы изготавливаются из сырого эбонита, очищенного в ритуале связывания с остатками даэдра, придающими предмету форму; сила оружия напрямую усиливается затяжными страданиями и яростью обитающего внутри даэдрота.",
		["daedric dai-katana"] = "Одни из самых редких и ценных сокровищ Тамриэля. Даэдрические дай-катаны изготавливаются из сырого эбонита, очищенного в ритуале связывания с остатками даэдра, придающими предмету форму; сила оружия напрямую усиливается затяжными страданиями и яростью обитающего внутри даэдрота. Происходя из таинственной земли Акавир, этот особый стиль клинка был завезен в Тамриэль после серии акавирских вторжений и поселений, в конечном итоге повлияв на Вторую Империю и распространив их по всем провинциям.",
