		-- Beasts
		["alit"] = "Заключенная душа Алита — всеядного родича Гуара и Кагути. Выделанная шкура Алита — обычный предмет и товар для эшлендеров, которые более охотно встречают их выступающие челюсти, чем клыки Кагути.",
		["alit_diseased"] = "Заключенная душа больного Алита, пораженного Атаксией — легкой распространенной болезнью, вызывающей общую боль и скованность мышц.",
		["alit_blighted"] = "Заключенная душа Алита, пораженного Черносердечной Гнилью — разновидностью древней болезни, разносимой с Красной Горы, поражающей силу и выносливость жертвы.",
		["cliff racer"] = "Заключенная душа Скального Наездника — агрессивных крылатых существ, наиболее опасных при встрече стаей. Их перья используются по всему Морровинду для украшения и изготовления оперения стрел. Легенда гласит, что именно легионы этих существ изгнали Драконов из Морровинда.",
		["cliff racer_diseased"] = "Заключенная душа больного Скального Наездника, пораженного Чертовой Немощью — легкой распространенной болезнью, вызывающей постоянное раздражение и воспаление суставов.",
		["cliff racer_blighted"] = "Заключенная душа Скального Наездника, пораженного Пепельной Язвой — разновидностью древней болезни, разносимой с Красной Горы, поражающей поведение жертвы.",
		["dreugh"] = "Заключенная душа Дроу — древних человекоподобных морских чудовищ, населяющих воды по всему Тамриэлю. Легенда гласит, что они — остатки некогда великой цивилизации, превратившиеся в простых монстров, на которых охотятся ради воска, соскабливаемого с их панцирей.",
		["dreugh_koal"] = "Заключенная душа Повелителя Дроу, убитого в пещере Коал — месте Святилища Доблести. Здесь, как говорят, лорд Вивек победил Красного Человека — отца дроу, пощадив его жизнь при условии, что его дети отдадут свои шкуры на службу данмерам.",
		["guar"] = "Заключенная душа Гуара — мягкого родича Алита и Кагути. Гуары служат основным домашним стадным и вьючным животным Морровинда, их разводят ради мяса и шкур. Легенда гласит, что именно полосатые гуары с равнин Дешаан, а также его проблемы с местным языком, привели Тибера Септима к тому, чтобы называть этих существ «тиграми» по аналогии со знакомой сказкой, что побудило имперцев и даже некоторых рабовладельцев Дрес называть их так.",
		["guar_feral"] = "Заключенная душа Одичавшего Гуара — мягкого родича Алита и Кагути. Несмотря на то, что большинство гуаров — существа мирные, некоторые остаются одичавшими и агрессивными, возможно, принадлежа к последним сохранившимся кровным линиям, не тронутым цивилизацией.",
		["guar_pack"] = "Заключенная душа Вьючного Гуара — мягкого родича Алита и Кагути. Гуары служат основным домашним стадным и вьючным животным Морровинда, их разводят ради мяса и шкур. Легенда гласит, что именно полосатые гуары с равнин Дешаан, а также его проблемы с местным языком, привели Тибера Септима к тому, чтобы называть этих существ «тиграми» по аналогии со знакомой сказкой, что побудило имперцев и даже некоторых рабовладельцев Дрес называть их так.",
		["guar_llovyn_unique"] = "Заключенная душа Корки — гуара, некогда принадлежавшего задолжавшему Лловину Андусу.",
		["guar_pack_tarvyn_unique"] = "",
		["guar_rollie_unique"] = "Заключенная душа Ролли — гуара, некогда принадлежавшего торговцу Терису Раледрану.",
		["guar_white_unique"] = "Заключенная душа Белого Гуара — уникального существа, появившегося во сне Уршамусы Рапли из лагеря Ахеммуса.",
		["guar_hrmudcrabnest"] = "Заключенная душа Гуара — мягкого родича Алита и Кагути. Гуары служат основным домашним стадным и вьючным животным Морровинда, их разводят ради мяса и шкур. Легенда гласит, что именно полосатые гуары с равнин Дешаан, а также его проблемы с местным языком, привели Тибера Септима к тому, чтобы называть этих существ «тиграми» по аналогии со знакомой сказкой, что побудило имперцев и даже некоторых рабовладельцев Дрес называть их так.",
		["kagouti"] = "Заключенная душа Кагути — мощного и агрессивного родича Гуара и Алита. Дикие кагути, как правило, путешествуют в одиночку или небольшими группами до брачного сезона, когда можно наблюдать доминирование самок этого вида. Те, кто готов встретить их острые клыки, используют шкуру кагути для изготовления прочной кожи.",
