		["dremora_lord"] = "Заключенная душа Лорда Дреморы — разумных человекоподобных даэдра, в первую очередь ассоциируемых с Мерунесом Дагоном. Они называют себя «Кин» и поддерживают развитое общество в Обливионе, разделенное на различные кланы и касты; их собственные ряды поднимаются и падают под сложной системой клятв и по воле их преданного Принца.",
		["dremora_special_fyr"] = "Заключенная душа Лорда Дрегаса Волари — дреморы, владевшей последним известным Даэдрическим Полумесяцем в своем святилище Магас Волар.",
		["golden saint"] = "Заключенная душа Золотого Святого — более известных как Ауреалы в пределах Обливиона, эти даэдра в первую очередь ассоциируются с Шеогоратом и его Безумными Пределами. В его сфере они поддерживают матриархальное общество и разделяют кастовую систему с восьмиуровневой иерархией, но находятся в постоянном соперничестве с мазкен, или Темными Соблазнительницами.",
		["golden saint_summon"] = "Заключенная душа Золотого Святого — более известных как Ауреалы в пределах Обливиона, эти даэдра в первую очередь ассоциируются с Шеогоратом и его Безумными Пределами. В его сфере они поддерживают матриархальное общество и разделяют кастовую систему с восьмиуровневой иерархией, но находятся в постоянном соперничестве с мазкен, или Темными Соблазнительницами.",
		["golden saint_staada"] = "Заключенная душа Стаады — Золотой Святой, посланной Шеогоратом, чтобы потревожить жрицу Азуры, давшую обет уединения.",
		["hunger"] = "Заключенная душа Голода — считающегося одним из слуг даэдрического принца Боэтии. Эти изможденные, долговязые даэдра известны тем, что атакуют длинным языком, а также вытянутыми когтями, нанося большой урон снаряжению своих жертв.",
		["hunger_audenian"] = "Заключенная душа Голода, призванного Ауденианом Валиусом для защиты его списка клиентов от воров.",
		["hunger_az_01"] = "Заключенная душа Голода. Этот даэдра был послан Шеогоратом, чтобы потревожить жрицу Азуры, давшую обет уединения.",
		["hunger_az_02"] = "Заключенная душа Голода. Этот даэдра был послан Шеогоратом, чтобы потревожить жрицу Азуры, давшую обет уединения.",
		["hunger_summon"] = "Заключенная душа Голода — считающегося одним из слуг даэдрического принца Боэтии. Эти изможденные, долговязые даэдра известны тем, что атакуют длинным языком, а также вытянутыми когтями, нанося большой урон снаряжению своих жертв.",
		["hunger_fghl"] = "Заключенная душа Голода, осквернившего родовую гробницу Сарано.",
		["ogrim"] = "Заключенная душа Огрима — одних из самых крупных и наименее разумных из даэдра. Их часто ассоциируют с Малакатом, и поэтому они напоминают его предполагаемых других детей — орков и гоблинскую родню.",
		["ogrim_az"] = "Заключенная душа Огрима. Этот даэдра был послан Шеогоратом, чтобы потревожить жрицу Азуры, давшую обет уединения.",
		["ogrim titan"] = "Заключенная душа Огрима-Титана — одних из самых крупных и наименее разумных из даэдра. Их часто ассоциируют с Малакатом, и поэтому они напоминают его предполагаемых других детей — орков и гоблинскую родню.",
		["scamp"] = "Заключенная душа Скампа — давно считающегося слугами Мерунеса Дагона. Скампы обычно служат под началом дремор и известны как слабые, тупые, трусливые и озорные. Однако, несмотря на их безобидное поведение, скампы, как известно, жестоко обращаются со своими жертвами и лакомятся их плотью.",
		["scamp_summon"] = "Заключенная душа Скампа — давно считающегося слугами Мерунеса Дагона. Скампы обычно служат под началом дремор и известны как слабые, тупые, трусливые и озорные. Однако, несмотря на их безобидное поведение, скампы, как известно, жестоко обращаются со своими жертвами и лакомятся их плотью.",
		["lustidrike"] = "Заключенная душа Лустидрика — скампа, преданного Шеогорату, который однажды предлагал бесплатные напитки в святилище Альд Дэдрот.",
		["scamp_mg_apprentice"] = "Заключенная душа Скампа, убитого в Хижине Хулина в Маар Гане, призванного учеником Хулина.",
		["scamp_creeper"] = "Заключенная душа Крипера — скампа-торговца, работающего в поместье Горак в Кальдере.",
		["dead_scamp"] = "Заключенная душа Скампа — давно считающегося слугами Мерунеса Дагона. Скампы обычно служат под началом дремор и известны как слабые, тупые, трусливые и озорные. Однако, несмотря на их безобидное поведение, скампы, как известно, жестоко обращаются со своими жертвами и лакомятся их плотью.",
		["scamp_dead"] = "Заключенная душа Скампа — давно считающегося слугами Мерунеса Дагона. Скампы обычно служат под началом дремор и известны как слабые, тупые, трусливые и озорные. Однако, несмотря на их безобидное поведение, скампы, как известно, жестоко обращаются со своими жертвами и лакомятся их плотью.",
		["winged twilight"] = "Заключенная душа Крылатой Сумерки — женственных даэдра, служащих посланницами Азуры, напоминающих звериных гарпий, обитающих в Хай Роке. Они имеют некоторое сходство с самими данмерами по внешнему виду, даэдрическая принцесса, очевидно, впечатлила сумеречных знакомой формой своих почитателей.",
		["winged twilight_summon"] = "Заключенная душа Крылатой Сумерки — женственных даэдра, служащих посланницами Азуры, напоминающих звериных гарпий, обитающих в Хай Роке. Они имеют некоторое сходство с самими данмерами по внешнему виду, даэдрическая принцесса, очевидно, впечатлила сумеречных знакомой формой своих почитателей.",
		["winged twilight_grunda_"] = "Заключенная душа Молаг Грунды — Крылатой Сумерки и дочери Молаг Бала, укрывшейся в пещере Дубдилла с Ледяным Атронахом Номегом Гаем.",
		-- Kwama
		["kwama forager"] = "Заключенная душа Квамы-Фуражира — агрессивных разведчиков улья, которые обследуют поверхность земли и подземные проходы в поисках подходящих мест для колонии и добычи. Хотя они нападают на чужаков, знакомый запах Яичных Шахтеров делает их довольно спокойными.",
		["kwama forager_tb"] = "Заключенная душа Квамы-Фуражира — агрессивных разведчиков улья, которые обследуют поверхность земли и подземные проходы в поисках подходящих мест для колонии и добычи. Хотя они нападают на чужаков, знакомый запах Яичных Шахтеров делает их довольно спокойными.",
		["kwama forager blighted"] = "Заключенная душа Квамы-Фуражира, пораженной Пепельной Язвой — разновидностью древней болезни, разносимой с Красной Горы, поражающей поведение жертвы.",
		["kwama queen"] = "Заключенная душа Королевы Квамы — самой крупной из квамы, производящей все яйца для улья. Королевы слишком велики, чтобы передвигаться, поэтому за ними ухаживают Квамы-Рабочие. Они считаются бесценными для владельцев и работников Шахт Яиц, являясь источником всего их дохода.",
		["kwama queen_hhem"] = "Заключенная душа Королевы Квамы из шахты яиц Инаниус, принадлежащей Серджо Авону Орану.",
		["kwama queen_mudan"] = "Заключенная душа Королевы Квамы из шахты яиц Мудан-Мул, пораженной Пепельной Язвой — разновидностью древней болезни, разносимой с Красной Горы, поражающей поведение жертвы.",
