		["fabricant_verminousdead"] = "Заключенная душа Вредоносного Фабриканта — таинственных существ, созданных загадочным Сотой Силом. Несмотря на их сходство с дварфийскими центурионами, Фабриканты отличаются тем, что они частично органические и содержат душу, возможно, происходящую из камня, который может питать существо.",
		["goblin_grunt"] = "Заключенная душа Гоблина-Пехотинца — примитивных гуманоидов, встречающихся по всему Тамриэлю, часто живущих в подземных клановых обществах. Среди гоблинской родни они ассоциируются с даэдрическим принцем Малакатом наряду с орками и ограми.",
		["goblin_footsoldier"] = "Заключенная душа Гоблина-Пехотинца — примитивных гуманоидов, встречающихся по всему Тамриэлю, часто живущих в подземных клановых обществах. Среди гоблинской родни они ассоциируются с даэдрическим принцем Малакатом наряду с орками и ограми.",
		["goblin_bruiser"] = "Заключенная душа Гоблина-Громилы — более способных бойцов в гоблинском клане. Среди гоблинской родни они ассоциируются с даэдрическим принцем Малакатом наряду с орками и ограми.",
		["goblin_handler"] = "Заключенная душа Гоблина-Дрессировщика — тех гоблинов, которые отвечают за выращивание, тренировку и уход за их обученными дурзогами. Среди гоблинской родни они ассоциируются с даэдрическим принцем Малакатом наряду с орками и ограми.",
		["goblin_officer"] = "Заключенная душа Гоблина-Офицера — лидеров небольших отрядов гоблинов и их дурзогов. Среди гоблинской родни они ассоциируются с даэдрическим принцем Малакатом наряду с орками и ограми.",
		["goblin_officeruni"] = "Заключенная душа Гоблина-Офицера — лидеров небольших отрядов гоблинов и их дурзогов. Среди гоблинской родни они ассоциируются с даэдрическим принцем Малакатом наряду с орками и ограми.",
		["goblin_warchief1"] = "Заключенная душа Вождя Дургока — одного из двух гоблинских вождей, возглавляющих собирающуюся армию под городом Морнхолд.",
		["goblin_warchief2"] = "Заключенная душа Вождя Курога — одного из двух гоблинских вождей, возглавляющих собирающуюся армию под городом Морнхолд.",
		["lich"] = "Заключенная душа Лича — могущественных волшебников, достигших бессмертия, поместив свою душу в объект, известный как Филактерия, став нежитью в процессе.",
		["lich_profane_unique"] = "Заключенная душа Нечестивого Аколита — одного из пяти личей, осквернивших Святилище Мертвых под городом Морнхолд.",
		["lich_relvel"] = "Заключенная душа Гедны Рельвель — «Лича Морнхолда». При жизни она была могущественной колдуньей, осужденной за использование запретной магии. Похороненная в руинах Старого Морнхолда, Рельвель вернулась как Лич и распространила древнюю Багровую Чуму по всему городу.",
		["lich_barilzar"] = "Заключенная душа Барилзара — создателя Запутанного Кольца, проклятого артефакта, лишенного большей части его разрушительной силы, так что только бог мог полностью его использовать. При жизни он был знаменитым и могущественным волшебником, учившимся у Соты Сила, но превратил себя в лича, чтобы охранять свое достойное сожаления творение от всех, кто мог бы им злоупотребить.",
		["ancestor_ghost_greater"] = "Заключенная душа Духа Предка — почитаемых духов данмерских прародителей, предлагающих помощь и защиту в обмен на признание. Их потомки обычно приносят им дары в Родовых Гробницах, и взамен они защищают семейные останки.",
		["ancestor_ghost_variner"] = "Заключенная душа Призрака Варинера — некогда мужа Нарисы Адус, убитого головорезами Банды «Черный Дротик».",
		["ghost_radac"] = "Заключенная душа Радака Штунгнтумза — двемерского Призрака, который был солдатом и оружейником в потерянном городе Бамз-Амшенд.",
		["almalexia"] = "Заключенная душа Амалексии — живой богини Трибунала. Амалексия почиталась как великая Исцеляющая-Мать данмеров и, жаждущая радикального обожания, сеяла обманчивые сказки так мастерски, что сама в них верила. Считаясь Предтечей Амалексии, Боэтия впечатлила на богине-королеве многие из собственных черт Даэдра, хотя приверженцы Храма отвергали ее характеристику как существа обмана, заговора и тайных планов убийств.",
		["almalexia_warrior"] = "Заключенная душа Амалексии — живой богини Трибунала. Амалексия почиталась как богиня-исцеляющая-мать данмеров и, жаждущая радикального обожания, сеяла обманчивые сказки так мастерски, что сама в них верила. Считаясь Предтечей Амалексии, Боэтия впечатлила на богине-королеве многие из собственных черт Даэдра, хотя приверженцы Храма отвергали ее характеристику как существа обмана, заговора и тайных планов убийств.",
		["imperfect"] = "Заключенная душа Несовершенного — продвинутого механического существа, которое когда-то стояло на страже Купола Соты Сила. Среди фактотумов — человекоподобных механических конструкций, созданных богом-королем Часового Города, Несовершенный является кульминацией бесчисленных прототипов, улучшаемых с каждым поражением. Хотя когда-то у него был аналог, похоже, он был уничтожен последним посетителем Соты Сила.",
		["scrib_rerlas"] = "Заключенная душа домашнего Скриба, проданного торговцем Рерласом Моном на Большом Базаре Морнхолда.",
		["rat_rerlas"] = "Заключенная душа домашней Крысы, проданной торговцем Рерласом Моном на Большом Базаре Морнхолда.",
		["rat_pack_rerlas"] = "Заключенная душа домашней Вьючной Крысы, проданной торговцем Рерласом Моном на Большом Базаре Морнхолда.",
		["dremora_lord_khash_uni"] = "Заключенная душа Хаш-Ти Дхрура — Дреморы, которая когда-то стояла на страже в святилище Норенен-Дур.",
		["rat_plague"] = "Заключенная душа Зараженной Крысы, пораженной Багровой Чумой — древней болезнью Второй Эры, которая лишь недавно вновь всплыла в городе Морнхолд.",
		["rat_plague_hall1"] = "Заключенная душа Зараженной Крысы, пораженной Багровой Чумой — древней болезнью Второй Эры, которая лишь недавно вновь всплыла в городе Морнхолд.",
		["rat_plague_hall1a"] = "Заключенная душа Зараженной Крысы, пораженной Багровой Чумой — древней болезнью Второй Эры, которая лишь недавно вновь всплыла в городе Морнхолд.",
		["rat_plague_hall2"] = "Заключенная душа Зараженной Крысы, пораженной Багровой Чумой — древней болезнью Второй Эры, которая лишь недавно вновь всплыла в городе Морнхолд.",
				-- Plugins
		["skeleton_fm_archer"] = "Заключенная душа Скелета-Лучника, оживленного в составе армии нежити, используемой личем Грурном для штурма островной крепости Файрмот.",
		["skeleton_fm_grunt"] = "Заключенная душа Скелета-Воителя, оживленного в составе армии нежити, используемой личем Грурном для штурма островной крепости Файрмот.",
		["skeleton_fm_king"] = "Заключенная душа Грурна — могущественного лича, который вышел из океана с армией нежити и захватил островную крепость Файрмот, забрав себе знаменитый Щит Акавира.",
		-- Spriggans and Twiggans
		["bm_twiggan"] = "Заключенная душа Твиггана — древесных духов, обитающих на острове Солстхейм. Согласно местным скаалам, когда Все-Создатель вдохнул жизнь в созданий их земли, это дыхание прошло и сквозь деревья, некоторые из которых сохранили частицу той жизни.",
		["bm_twiggan_groot"] = "Заключенная душа странного Твиггана по имени Грут — древесного духа, обитающего на острове Солстхейм. Согласно местным скаалам, когда Все-Создатель вдохнул жизнь в созданий их земли, это дыхание прошло и сквозь деревья, некоторые из которых сохранили частицу той жизни.",
		-- Quorn Resource Integration
		["ash_ghoul_hooded"] = "Заключенная душа Пепельного Гуля в капюшоне — второй по степени прогрессии формы, которую принимают те, кто принимает Божественную Болезнь и достаточно силен, чтобы выдержать силу Дагот Ура. Когда-то полое пространство на их лицах заполнилось флейтоподобным хоботком — физическим признаком их способности направлять мелодическое влияние Дагот Ура своим последователям, делая это посредством поэзии. Пепельные Гули, которые стали особенно просветленными благодаря сну своего лорда, известны как Пепельные Поэты и носят имя Дагот.",
		["dremora_lord2"] = "Заключенная душа Лорда Дреморы — разумных человекоподобных даэдра, в первую очередь ассоциируемых с Мерунесом Дагоном. Они называют себя «Кин» и поддерживают развитое общество в Обливионе, разделенное на различные кланы и касты; их собственные ряды поднимаются и падают под сложной системой клятв и по воле их преданного Принца.",
		["dremora_lord3"] = "Заключенная душа Лорда Дреморы — разумных человекоподобных даэдра, в первую очередь ассоциируемых с Мерунесом Дагоном. Они называют себя «Кин» и поддерживают развитое общество в Обливионе, разделенное на различные кланы и касты; их собственные ряды поднимаются и падают под сложной системой клятв и по воле их преданного Принца.",
		["goblin_worker01"] = "Заключенная душа Гоблина-Рабочего — простых работников внутри гоблинского клана. Среди гоблинской родни они ассоциируются с даэдрическим принцем Малакатом наряду с орками и ограми.",
		["goblin_worker02"] = "Заключенная душа Гоблина-Чернорабочего — простых работников внутри гоблинского клана. Среди гоблинской родни они ассоциируются с даэдрическим принцем Малакатом наряду с орками и ограми.",
		-- Kogoruhn Expanded
		["dk_bell_ringer"] = "Заключенная душа Звонаря — извращенного слуги Шестого Дома, защищавшего крепость Когорухн с помощью волшебного колокола.",
		-- Mage Robes
		["mg_cr_s-fish_blind"] = "Заключенная душа Слепой Рыбы-Убийцы — агрессивной рыбы с острыми как бритва зубами, приспособленной к выживанию в темных глубинах Тамриэля, часто нападающей стаями. Их чешуя и икра ценятся в каждой провинции за свои алхимические свойства.",
		["mg_cr_bat"] = "Заключенная душа Летучей Мыши — ночных летающих созданий, распространенных по всем провинциям Тамриэля и известных нападениями стаями.",
		["mg_cr_bat_bogus"] = "Заключенная душа Летучей Мыши — ночных летающих созданий, распространенных по всем провинциям Тамриэля и известных нападениями стаями.",
		-- R-Zero's Creatorium Part I
		["r0_dreugh_land"] = "Заключенная душа Наземного Дроу — древнего человекоподобного морского чудовища, которое прошло процесс карвиназима, выйдя на сушу на год своей жизни, где становится агрессивным производителем потомства, лишенным своего обычного интеллекта. По прошествии года они проходят мефф, где переваривают ранее адаптированную кожу и органы, срыгивая их в виде свернувшихся волокнистых шариков, называемых громами. Легенда гласит, что они — остатки некогда великой цивилизации, превратившиеся в простых монстров, на которых охотятся ради воска, соскабливаемого с их панцирей.",
		["r0_dreugh_man'o'war"] = "Заключенная душа Дроу-Боевого Корабля — выносливого фенотипа древних человекоподобных морских чудовищ, населяющих воды по всему Тамриэлю. Легенда гласит, что они — остатки некогда великой цивилизации, превратившиеся в простых монстров, на которых охотятся ради воска, соскабливаемого с их панцирей.",
		["r0_mudcrab_king"] = "Заключенная душа Короля-Краба — родича твердопанцирных существ, различные виды которых можно найти на побережьях по всему Тамриэлю. Короли-Крабы отличаются острыми шипами на своих панцирях, и ловцы крабов обычно их избегают из-за их большей силы.",
		["r0_mudcrab_titan"] = "Заключенная душа Краба-Титана — родича твердопанцирных существ, различные виды которых можно найти на побережьях по всему Тамриэлю. Крабы-Титаны отличаются прочными, часто покрытыми ракушками панцирями. Хотя они напоминают легендарного Скара из Альд'Руна, их связь с легендарными Император-Крабами неизвестна.",
		["r0_slaughterfish_blind"] = "Заключенная душа Слепой Рыбы-Убийцы — агрессивной рыбы с острыми как бритва зубами, обитающей в подземных водах по всему Тамриэлю, часто нападающей стаями. Их чешуя и икра ценятся в каждой провинции за свои алхимические свойства.",
		["r0_slaughterfish_shock"] = "Заключенная душа Электрической Рыбы-Убийцы — агрессивной рыбы с острыми как бритва зубами и редкой способностью проводить электричество, обитающей в водах по всему Тамриэлю, часто нападающей стаями. Их чешуя и икра ценятся в каждой провинции за свои алхимические свойства.",
		-- Face of the Hortator
		["1fh_hunger_mephala"] = "Заключенная душа Голода, охранявшего Третью Печать Склепа в раскопанном храме Ашур-Анит.",
		["1fh_daedroth_boethiah"] = "Заключенная душа Даэдрота, охранявшего Первую Печать Склепа в раскопанном храме Ашур-Анит.",
		-- Undead Glass Berserker
		["undeadglassberserker"] = "Заключенная душа Неживого Стеклянного Берсерка — могущественного стража-предка, используемого данмерами для защиты своих гробниц и ценного имущества.",
		["undeadglassberserkeruni"] = "Заключенная душа Неживого Стеклянного Берсерка, побежденного при защите лавки Дроноса Ллерву на нижнем уровне Башни Сумерек у Призрачных Врат.",
		-- Better Dwarven Spectres - Mer and Maidens Edition
		["dwarven ghost fem"] = "Заключенная душа двемерского Призрака — неприкаянных духов, предположительно тех двемеров, которые умерли до событий у Красной Горы, избежав таинственной участи своих сородичей. Они остаются одними из немногих источников, из которых можно узнать секреты двемеров, если встретить достаточно сговорчивого духа.",
		-- Salt Gems of Bensamsi
		["md_ash_zombie"] = "Заключенная душа Наполненного Пепельного Зомби, захваченного Джитой-Нан для использования в его исследованиях в пещерах Бенсамси.",
		["md_ash_zombie_gem"] = "Заключенная душа Кристаллизующегося Пепельного Зомби, чья связь с Дагот Уром была разорвана в результате исследований Джиты-Нан.",
		["md_ash_zombie_gem_fresh"] = "Заключенная душа Кристаллизующегося Пепельного Зомби, чья связь с Дагот Уром была разорвана в результате исследований Джиты-Нан.",
		-- Ashes and Gold
		["pa_ag_clannfear"] = "Заключенная душа Кланфура, призванного поклонниками даэдра, которые похитили торговцев Кальдеры.",
		["pa_ag_daedroth"] = "Заключенная душа Даэдрота, призванного поклонниками даэдра, которые похитили торговцев Кальдеры.",
		["pa_dremora"] = "Заключенная душа Дреморы, призванной поклонниками даэдра, которые похитили торговцев Кальдеры.",
		-- Expedition to Mzelthuand
		["dd_2_dreugh_clockwork"] = "Заключенная душа Часового Дроу, встреченного в дварфийском исследовательском комплексе Мзелтуанд.",
		-- OAAB Data
		["ab_dae_darkseducer"] = "Заключенная душа Темной Соблазнительницы — более известной как Мазкен в пределах Обливиона, эти даэдра в первую очередь ассоциируются с Шеогоратом и его Безумными Пределами. В его сфере они поддерживают матриархальное общество и разделяют кастовую систему с семиуровневой иерархией, но находятся в постоянном соперничестве с ауреалами, или Золотыми Святыми.",
		["ab_dae_herne"] = "Заключенная душа Херна — разумного малого даэдра, родственного более распространенному Скампу и ассоциируемого с Мерунесом Дагоном.",
		["ab_fau_bat"] = "Заключенная душа Летучей Мыши — ночных летающих созданий, распространенных по всем провинциям Тамриэля и известных нападениями стаями.",
		["ab_fau_kwamagrubber"] = "Заключенная душа Пожирателя Личинок Квамы — недавно родившегося рабочего улья, сосредоточенного на потреблении питательных веществ для затвердевания своего все еще мягкого панциря.",
		["ab_fau_ratpassive"] = "Заключенная душа Крысы — распространенных грызунов, встречающихся по всему Тамриэлю и в различных его условиях. Хотя их мясо жесткое и жирное, оно дешево и в изобилии; его терпят самые бедные люди, приправляя сильными специями.",
		["ab_fau_sfishblind"] = "Заключенная душа Слепой Рыбы-Убийцы — агрессивной рыбы с острыми как бритва зубами, обитающей в подземных водах по всему Тамриэлю, часто нападающей стаями. Их чешуя и икра ценятся в каждой провинции за свои алхимические свойства.",
		["ab_fau_siltstrider01"] = "Заключенная душа Сильд-Страйдера — огромных членистоногих, обычно используемых как средство передвижения по Морровинду с помощью манипуляции открытыми органами и тканями; их хитиновые панцири выдолблены, чтобы создать пространство для пассажиров.",
		["ab_fau_spiderparasol"] = "Заключенная душа Паука-Зонтика — плотоядных паукообразных, которые подстерегают добычу у корней телваннских башен, сливаясь с окружающей средой благодаря окраске, соответствующей окружающим грибам.",
		["ab_fau_spiderparasolbby"] = "Заключенная душа Паука-Зонтика — плотоядных паукообразных, которые подстерегают добычу у корней телваннских башен, сливаясь с окружающей средой благодаря окраске, соответствующей окружающим грибам.",
		["ab_und_glassberserker"] = "Заключенная душа Неживого Стеклянного Берсерка — могущественного стража-предка, используемого данмерами для защиты своих гробниц и ценного имущества.",
	}
