		["ingred_gold_kanet_01"] = "Лепестки золотого цветущего растения, чаще всего встречающегося в Аскадийских островах и на Побережье Азуры.",
		["ingred_gravedust_01"] = "Порошок, извлеченный из останков, захороненных на освященной земле, обладает сродством к духам.",
		["ingred_green_lichen_01"] = "Корневой образец выносливого примитивного растения, растущего в Аскадийских островах и на Побережье Азуры.",
		["ingred_guar_hide_01"] = "Невыделанная шкура местного гуара, часто дубится для получения популярной кожи, используемой в местной одежде, доспехах и домашней утвари.",
		["ingred_hackle-lo_leaf_01"] = "Вкусный, съедобный, сочный лист Злачных Земель, ценится за вкус и восстановительные силы.",
		["ingred_heather_01"] = "Лепестки низкорослого вечнозеленого кустарника Аскадийских островов, известного своими мелкими розовато-пурпурными цветами.",
		["ingred_hound_meat_01"] = "Плоть местной никс-гончей, популярная за свои сладкие и нежные качества.",
		["ingred_bc_hypha_facia"] = "Светло-коричневый трутовик, собранный со стволов деревьев в регионе Берега Горечи.",
		["ingred_kagouti_hide_01"] = "Невыделанная шкура дикого клыкастого кагути, обычно используемая для изготовления прочной кожи для одежды и домашней утвари.",
		["ingred_kresh_fiber_01"] = "Смолистое волокно из грубой травы Злачных Земель и Побережья Азуры.",
		["ingred_kwama_cuttle_01"] = "Твердое воскообразное вещество, образующееся на клювах квамы.",
		["food_kwama_egg_02"] = "Питательный пищевой продукт, добываемый в ульях квамы Морровинда и популярный по всей Империи. Легко транспортируется благодаря долгому хранению, добыча яиц квамы — прибыльная промышленность на Вварденфелле.",
		["ingred_russula_01"] = "Приземистый, пестрый коричнево-зеленый гриб-поганка из региона Берега Горечи.",
		["ingred_marshmerrow_01"] = "Тростник, содержащий вкусную сладкую мякоть, которая при употреблении в свежем или приготовленном виде обладает скромными целебными свойствами. Маршмерроу — важная товарная культура ферм и плантаций Аскадийских островов, но также растет в дикой природе в Злачных землях и на Побережье Азуры.",
		["ingred_moon_sugar_01"] = "Зернистый порошок из мелких белых кристаллов, очищенных из тростниковых трав на побережьях и в эстуариях Эльсвера. Используемый как пряность в Эльсвере, он считается сильным наркотиком и запрещен в Морровинде и остальной Империи. Преступники пытались выращивать сахарно-лунные травы на Вварденфелле, безуспешно.",
		["ingred_muck_01"] = "Влажное, волокнистое месиво из измельченных губок-трясинниц, растущих в Вест-Гэше и на Побережье Азуры. Если его не приготовить должным образом, как это делают местные жители, оно слабо токсично.",
		["ingred_netch_leather_01"] = "Выделанная шкура местного нетча, популярная по всей Империи благодаря своей прочности, гибкости и различным цветам, что делает ее важным экспортным продуктом округа Вварденфелл.",
		["ingred_pearl_01"] = "Гладкие, круглые, блестящие бусины, ценимые для украшения. Жемчуг иногда производят коллопы и другие местные моллюски Морровинда; их редкость увеличивает рыночную стоимость.",
		["ingred_racer_plumes_01"] = "Перья местной птицеподобной скальной наездницы используются по всему Морровинду и за его пределами для изготовления оперения стрел, а также для украшения одежды и домашней утвари.",
		["ingred_rat_meat_01"] = "Жесткое и жирное мясо с неприятным запахом и вкусом. Тем не менее, оно дешево, его много, и оно питательно, если приготовить в тушеном виде и приправить сильными специями.",
		["ingred_raw_ebony_01"] = "Эбонит — одно из самых ценных веществ в Империи, в высокой концентрации встречающееся на острове Вварденфелл. Поэтому этот материал охраняется имперским законом, и его добыча и экспорт без лицензии запрещены. Чрезвычайно твердое, прочное, черное стеклоподобное вещество, эбонит, как говорят, является кристаллизовавшейся кровью богов.",
		["ingred_raw_glass_01"] = "Молочно-белый полупрозрачный зеленый материал, добываемый по всему Тамриэлю для изготовления эффективных, но легких и гибких доспехов. В основном ассоциируется с альтмерами, элегантность стекла делает его популярным в использовании у всех видов эльфов.",
		["ingred_red_lichen_01"] = "Корневой образец выносливого примитивного растения, растущего в суровых условиях Красной Горы, Молаг Амура и Пепельных земель.",
		["ingred_resin_01"] = "Твердые растворимые вещества растительного происхождения, используемые данмерами в качестве клеев и загустителей при производстве их уникальных хитиновых и костяных доспехов и оружия.",
		["ingred_roobrush_01"] = "Ветка жесткого, низкого, жилистого кустарника, растущего в засушливых, бедных, пепельных почвах Вест-Гэша.",
		["ingred_ruby_01"] = "Прозрачные красные драгоценные камни, которые иногда появляются на поверхности и чаще — в подземных отложениях по всему Тамриэлю.",
		["ingred_saltrice_01"] = "Вкусный и питательный пищевой продукт, выращиваемый в первую очередь как экспортная культура фермерами и владельцами плантаций Морровинда. Хотя большая часть импортных поставок Империи поступает с равнин Дешаан на материке, на Аскадийских островах Вварденфелла процветают новые фермы.",
		["ingred_scales_01"] = "Высушенная чешуя рыбы-убийцы. Говорят, что это «хрустящее лакомство» при приготовлении на местный манер, в отличие от мучнистого и зловонного качества мяса этого существа.",
		["ingred_scamp_skin_01"] = "Магическая плоть, снятая со Скампа во время его кратковременного проявления на смертном плане. Поскольку более сильные даэдра представляют большую опасность, на скампов особенно охотятся фермеры по добыче шкур.",
		["ingred_scathecraw_01"] = "Мягкая внутренняя мякоть длинной, жесткой, красноватой травы, растущей в термальных пепельных регионах Пепельных земель, Молаг Амура и Красной Горы.",
		["ingred_scrap_metal_01"] = "Ржавые куски экзотического металла, извлеченные из двемерских анимункули. Такой металл редок и драгоценен, ценится как коллекционерами древностей, так и знатоками металлов и чар.",
		["ingred_scrib_jelly_01"] = "Питательное, но кислое на вкус желе, производимое скрибами — личиночной формой квамы.",
		["ingred_scrib_jerky_01"] = "Пищевой продукт, приготовленный путем нарезки местных скрибов на полоски и сушки на солнце. Это блюдо, которое в испорченном виде по вкусу почти не отличается от свежего, является практичным выбором для выносливых путешественников.",
		["ingred_scuttle_01"] = "Сыроподобное жирное вещество, сделанное из мяса местных жуков, которое на удивление вкусно и считается одним из лучших блюд Вварденфелла.",
		["ingred_shalk_resin_01"] = "Твердые растворимые вещества, извлеченные из шкур местных шальков, используемые в качестве клеев и загустителей при производстве костяных и хитиновых доспехов.",
		["ingred_sload_soap_01"] = "Воскообразное вещество, сделанное из незрелых, неразумных форм слодов.",
		["food_kwama_egg_01"] = "Питательный пищевой продукт, добываемый в ульях квамы Морровинда и популярный по всей Империи. Легко транспортируется благодаря долгому хранению, добыча яиц квамы — прибыльная промышленность на Вварденфелле.",
		["ingred_bc_spore_pod"] = "Зеленый стручок, собранный с местного папоротника-тины, с Берега Горечи.",
		["ingred_stoneflower_petals_01"] = "Лепестки, собранные с маленького, распространенного голубого цветка Аскадийских островов и Побережья Азуры.",
		["ingred_trama_root_01"] = "Толстый, горький на вкус корень куста трамы, в основном используемый для заваривания успокаивающего чая. Эти кусты растут в пепельных почвах Пепельных земель, Молаг Амура и Красной Горы.",
		["ingred_vampire_dust_01"] = "Зернистый пеплоподобный порошок, собранный исключительно с иссохших трупов убитых вампиров, представляющий интерес в первую очередь для некромантов и алхимиков.",
		["ingred_coprinus_01"] = "Высокий, стройный гриб со светло-зеленой шляпкой, встречающийся вдоль Берега Горечи.",
		["ingred_void_salts_01"] = "Кристаллические осадки, собранные с останков Штормовых Атронахов, изгнанных из смертного плана.",
		["ingred_wickwheat_01"] = "Коричневые стебли дикой пепельной зерновой культуры, чаще всего встречающиеся в Злачных землях.",
		["ingred_willow_anther_01"] = "Пыльцевая часть цветка ивы, ценимая за порошкообразный остаток внутри, встречается в основном в Аскадийских островах и на Побережье Азуры.",
		["ingred_6th_corprusmeat_05"] = "Метастазы зараженной плоти и кожи, выращенные пораженными корпусом. Эти куски мяса хранятся для употребления пораженными или для участия в ритуалах, проводимых приверженцами Шестого Дома.",
		["ingred_6th_corprusmeat_01"] = "Метастазы зараженной плоти и кожи, выращенные пораженными корпусом. Эти завернутые куски мяса хранятся для употребления пораженными или для участия в ритуалах, проводимых приверженцами Шестого Дома.",
		["ingred_6th_corprusmeat_06"] = "Метастазы зараженной плоти и кожи, выращенные пораженными корпусом. Эти куски мяса хранятся для употребления пораженными или для участия в ритуалах, проводимых приверженцами Шестого Дома.",
		["ingred_6th_corprusmeat_03"] = "Метастазы зараженной плоти и кожи, выращенные пораженными корпусом. Эти завернутые куски мяса хранятся для употребления пораженными или для участия в ритуалах, проводимых приверженцами Шестого Дома.",
		["ingred_6th_corprusmeat_07"] = "Метастазы зараженной плоти и кожи, выращенные пораженными корпусом. Эти куски мяса хранятся для употребления пораженными или для участия в ритуалах, проводимых приверженцами Шестого Дома.",
		["ingred_6th_corprusmeat_02"] = "Метастазы зараженной плоти и кожи, выращенные пораженными корпусом. Эти завернутые куски мяса хранятся для употребления пораженными или для участия в ритуалах, проводимых приверженцами Шестого Дома.",
		["ingred_6th_corprusmeat_04"] = "Метастазы зараженной плоти и кожи, выращенные пораженными корпусом. Эти завернутые куски мяса хранятся для употребления пораженными или для участия в ритуалах, проводимых приверженцами Шестого Дома.",
		["ingred_bread_01_uni2"] = "Хлеб — обычный пищевой продукт, встречающийся по всему Тамриэлю, хотя в каждой провинции его готовят по-разному.",
		["ingred_cursed_daedras_heart_01"] = "Магический орган, извлеченный из малых даэдра во время их кратковременного проявления на смертном плане.",
		["ingred_dae_cursed_diamond_01"] = "Редкий, прозрачный, чрезвычайно твердый драгоценный камень большой ценности.",
		["ingred_dae_cursed_emerald_01"] = "Прозрачный зеленый драгоценный камень со скромными магическими свойствами.",
		["ingred_human_meat_01"] = "Плоть, снятая со смертного для каких-то извращенных целей.",
		["ingred_scrib_jelly_02"] = "Странная слизь, обнаруженная на растении по имени Чарльз в «Редких книгах Джобаши» в Вивеке.",
		["ingred_bread_01_uni3"] = "Выпечка, некогда принадлежавшая Гаккенфельду — орку с плантации Гро-Баграт.",
		["ingred_dae_cursed_pearl_01"] = "Гладкие, круглые, блестящие бусины, ценимые для украшения. Жемчуг иногда производят коллопы и другие местные моллюски Морровинда; их редкость увеличивает рыночную стоимость.",
		["poison_goop00"] = "Токсичное вещество, сваренное алхимиком для какой-то неизвестной цели.",
		["ingred_dae_cursed_raw_ebony_01"] = "Эбонит — одно из самых ценных веществ в Империи, в высокой концентрации встречающееся на острове Вварденфелл. Поэтому этот материал охраняется имперским законом, и его добыча и экспорт без лицензии запрещены. Чрезвычайно твердое, прочное, черное стеклоподобное вещество, эбонит, как говорят, является кристаллизовавшейся кровью богов.",
		["ingred_dae_cursed_ruby_01"] = "Прозрачные красные драгоценные камни, которые иногда появляются на поверхности и чаще — в подземных отложениях на Вварденфелле.",
		["ingred_treated_bittergreen_uniq"] = "Лепестки горькозелени, пропитанные токсичным веществом, полученные от Тароса Драла для убийства.",
		-- Tribunal
		["ingred_adamantium_ore_01"] = "Редкий, блестящий металл, чаще всего используемый для изготовления оружия и доспехов. Адамантит — материал, ценимый в первую очередь альтмерами за его способность к зачарованию, но использовавшийся большинством эльфийских рас.",
		["ingred_durzog_meat_01"] = "Жесткое мясо местного дурзога — разумных зверей, в просторечии известных как «грязевые щенки».",
		["ingred_golden_sedge_01"] = "Лепестки, собранные с растения золотая осока, встречающегося в основном на материке Морровинда.",
		["ingred_horn_lily_bulb_01"] = "Крупная луковица, собранная с пурпурной лилии-рога, растения, встречающегося в основном на материке Морровинда.",
		["ingred_lloramor_spines_01"] = "Крупная колючка, вырванная из колючего ллорамора — разновидности кактуса, произрастающего на материке Морровинда.",
		["ingred_meadow_rye_01"] = "Серебристое зерно, собранное с луговой ржи — длинной травы, выращиваемой как альтернатива пшенице на материке Морровинда.",
		["ingred_nirthfly_stalks_01"] = "Жилистый стебель, сорванный с растения ниртфлай, встречающегося на материках Морровинда.",
		["ingred_noble_sedge_01"] = "Пурпурные лепестки, собранные с благородной осоки — цветущего растения, произрастающего в Морровинде.",
		["ingred_scrib_cabbage_01"] = "Листовая головка капусты скрибов — овоща, который по-разному готовят на материке Морровинда.",
		["ingred_sweetpulp_01"] = "Сладкая мякоть, собранная изнутри кактуса сладкая бочка, растения, встречающегося на материке Морровинда.",
		["ingred_timsa-come-by_01"] = "Красивые розовые лепестки, сорванные с цветущего растения тимса-кам-бай, которым популярно украшают внешнюю сторону многих домов на материке Морровинда.",
		-- Bloodmoon
		["ingred_bear_pelt"] = "Невыделанная шкура бурого медведя — огромного зверя, обитающего на острове Солстхейм.",
		["ingred_boar_leather"] = "Полоски выделанной шкуры щетиноспинного вепря — свирепого клыкастого существа, обитающего на Солстхейме.",
		["ingred_eyeball"] = "Глаз, извлеченный из головы граля — огромного клыкастого существа с Солстхейма, также известного как ледяной тролль.",
		["ingred_gravetar_01"] = "Жирное вещество, которое, кажется, вытекает из нордской нежити — драугров — после поражения.",
		["ingred_heartwood_01"] = "Волшебная древесина, добытая из спригганов. Согласно скаальской легенде, она слабо сохраняет частицу той жизненной сущности, которую Все-Создатель вдохнул в мир.",
		["ingred_holly_01"] = "Красные ягоды, собранные с остролиста — вечнозеленого растения, произрастающего на острове Солстхейм.",
		["ingred_horker_tusk_01"] = "Тонкий бивень, собранный с хоркера — плавниковых амфибийных существ, усеивающих пляжи Солстхейма.",
		["ingred_raw_stalhrim_01"] = "Редкий зачарованный лед, используемый древними нордами в их погребальных ритуалах. Не может быть добыт обычными средствами, но может быть использован для создания мощного оружия и доспехов теми, кто обучен этому искусству.",
		["ingred_belladonna_01"] = "Созревшие ягоды кустарника белладонны — маленького растения, встречающегося в более теплых регионах Солстхейма.",
		["ingred_belladonna_02"] = "Незрелые ягоды кустарника белладонны — маленького растения, встречающегося в более теплых регионах Солстхейма.",
		["ingred_snowbear_pelt_unique"] = "Невыделанная шкура снежного медведя — огромного зверя, идеально приспособленного к окружающей среде Солстхейма.",
		["ingred_snowwolf_pelt_unique"] = "Невыделанная шкура снежного волка — проворного зверя, идеально приспособленного к окружающей среде Солстхейма.",
		["ingred_wolf_pelt"] = "Невыделанная шкура волка — проворного зверя, обитающего на острове Солстхейм.",
		["ingred_wolfsbane_01"] = "Пурпурные лепестки, собранные с волчьего аконита — чрезвычайно редкого цветущего растения, которое, как говорят, растет только в одном месте на острове Солстхейм.",
		-- Kogoruhn Expanded
		["dk_ingred_player_meat_01"] = "Небольшой кусок вашей собственной плоти, который нужно съесть на пиру в Когорухне.",
		["dk_obsidian"] = "Сырой кусок вулканического стекла, способный нагреть Обсидиановую Кузницу Когорухна.",
		-- OAAB Data
		["ab_dri_guarmilk"] = "С давних пор считающееся основным продуктом данмерской диеты, гуарье молоко — это обманчиво названный напиток и кулинарный ингредиент, получаемый из отрыгиваний одомашненных гуаров. Это густая, богатая питательными веществами слюна, производство которой стимулируется специальными диетами и периодическим голоданием стада.",
		["ab_dri_musa"] = "Названный в честь племени эшлендеров Ахеммуса, которые особенно жалуют этот напиток, муса — это крепкий местный ликер из жуков, давно производимый велоти, хотя его сильный вкус и аромат делают его редким зрелищем за пределами их собственных лагерей.",
		["ab_dri_tramatea"] = "Особенно популярный в пепельных регионах Морровинда, где растение в изобилии, чай из трамы заваривается из одноименного корня и издавна считается путешественниками отличным источником жизненной силы.",
		["ab_dri_yamuz"] = "",
		["ab_eff_kwamapoison"] = "",
	}
